class FixedWindowLimiter:
    def __init__(self, limit, window_seconds):
        self.limit = limit
        self.window_seconds = window_seconds
        self.windows = {}

    def allow(self, key, timestamp):
        window = int(timestamp // self.window_seconds)
        cur_window, count = self.windows.get(key, (None, 0))
        if cur_window != window:
            count = 0
            cur_window = window
        if count < self.limit:
            self.windows[key] = (cur_window, count + 1)
            return True
        self.windows[key] = (cur_window, count)
        return False
